mapper.select:
SELECT 
FROM biz_notice n
LEFT JOIN sys_user u ON n.publisher_id = u.id

    n.is_deleted = 0

        AND n.title LIKE CONCAT('%', #{title}, '%')


        AND n.type = #{type}


        AND n.status = #{status}


        AND n.visibility = #{visibility}


        AND u.real_name LIKE CONCAT('%', #{publisherName}, '%')


ORDER BY n.create_time DESC
